using namespace std;

struct Book {
    string title;
    int stock;
};

class BookProcessor {
public:
    virtual void Process(vector<Book>& books) = 0;
};

class LowStockFilter : public BookProcessor {
public:
    void Process(vector<Book>& books) override {
        for (auto& b : books) {
            if (b.stock < 5) cout << b.title << " 재고 부족" << endl;
        }
    }
};

void processBooks(vector<Book>& books, BookProcessor& processor) {
    processor.Process(books);
}

int main() {
    vector<Book> books = { { "C++", 2 }, { "Vue", 10 } };
    LowStockFilter filter;
    processBooks(books, filter);
    return 0;
}

