void FindMinMax(int arr[], int size, int* minOut, int* maxOut) {
    *minOut = arr[0];
    *maxOut = arr[0];
    for (int i = 1; i < size; i++) {
        if (arr[i] < *minOut) *minOut = arr[i];
        if (arr[i] > *maxOut) *maxOut = arr[i];
    }
}

int main() {
    int arr[] = { 5, 2, 8, 1, 9 };
    int minVal, maxVal;
